1	//! Default-off timing records for the low-frequency transfer lifecycle.
2	//!
3	//! These records surround session establishment and command handling. They are
4	//! deliberately separate from the schema-1 `[session-phase]` stream, which
5	//! remains the detailed observer for an established transfer session.
6	
7	use super::session_phase::{session_trace_id, trace_env_run_id, SessionPhaseRole};
8	use serde::Serialize;
9	use std::io::Write;
10	use std::sync::atomic::{AtomicU64, Ordering};
11	use std::sync::{Arc, OnceLock};
12	use std::time::{Instant, SystemTime, UNIX_EPOCH};
13	
14	/// Result recorded on a lifecycle boundary that completed.
15	#[derive(Clone, Copy, Debug, Eq, PartialEq, Serialize)]
16	#[serde(rename_all = "SCREAMING_SNAKE_CASE")]
17	pub enum TransferLifecycleOutcome {
18	    Success,
19	    Refused,
20	    Error,
21	}
22	
23	/// One structured lifecycle timing record.
24	#[derive(Clone, Debug, Serialize)]
25	pub struct TransferLifecycleEvent {
26	    pub schema: u8,
27	    pub run_id: String,
28	    pub producer_seq: u64,
29	    pub unix_ns: u128,
30	    pub elapsed_ns: u128,
31	    pub event: &'static str,
32	    #[serde(skip_serializing_if = "Option::is_none")]
33	    pub initiator_role: Option<SessionPhaseRole>,
34	    #[serde(skip_serializing_if = "Option::is_none")]
35	    pub session_id: Option<String>,
36	    #[serde(skip_serializing_if = "Option::is_none")]
37	    pub outcome: Option<TransferLifecycleOutcome>,
38	}
39	
40	type EventEmitter = dyn Fn(TransferLifecycleEvent) + Send + Sync + 'static;
41	type FlushEmitter = dyn Fn() + Send + Sync + 'static;
42	
43	enum LifecycleWriterOutput {
44	    Line(String),
45	    Flush,
46	}
47	
48	struct LifecycleContext {
49	    run_id: Arc<str>,
50	    origin: Instant,
51	    producer_seq: AtomicU64,
52	    initiator_role: OnceLock<SessionPhaseRole>,
53	    session_id: OnceLock<Arc<str>>,
54	    emit: Arc<EventEmitter>,
55	    flush: Arc<FlushEmitter>,
56	}
57	
58	/// Explicit, cloneable context for one initiating transfer process.
59	///
60	/// [`TransferLifecycleTrace::from_env`] is the production constructor. It
61	/// stays disabled unless the existing `BLIT_TRACE_SESSION_PHASES` flag is
62	/// truthy, and uses `BLIT_TRACE_RUN_ID` for cross-process correlation.
63	#[derive(Clone, Default)]
64	pub struct TransferLifecycleTrace {
65	    context: Option<Arc<LifecycleContext>>,
66	}
67	
68	impl TransferLifecycleTrace {
69	    /// Create the production context at the earliest observable caller stamp.
70	    pub fn from_env() -> Self {
71	        Self::from_env_with(|name| std::env::var(name).ok(), Self::stderr_writer)
72	    }
73	
74	    /// Build a deterministic capture context without consulting process
75	    /// environment or starting a writer thread.
76	    pub fn capture(
77	        run_id: impl Into<String>,
78	        emit: impl Fn(TransferLifecycleEvent) + Send + Sync + 'static,
79	    ) -> Self {
80	        Self::capture_with_flush(run_id, emit, || {})
81	    }
82	
83	    /// Build a deterministic capture context with an observable flush hook.
84	    pub fn capture_with_flush(
85	        run_id: impl Into<String>,
86	        emit: impl Fn(TransferLifecycleEvent) + Send + Sync + 'static,
87	        flush: impl Fn() + Send + Sync + 'static,
88	    ) -> Self {
89	        Self::with_emitters(
90	            run_id.into(),
91	            Instant::now(),
92	            Arc::new(emit),
93	            Arc::new(flush),
94	        )
95	    }
96	
97	    /// Force lifecycle tracing off without consulting process environment.
98	    pub fn disabled() -> Self {
99	        Self { context: None }
100	    }
101	
102	    /// Whether this context will emit lifecycle records.
103	    pub fn is_enabled(&self) -> bool {
104	        self.context.is_some()
105	    }
106	
107	    /// Attach the semantic role once route selection makes it known. The first
108	    /// attachment wins so clones cannot race the context into inconsistent
109	    /// correlation fields.
110	    pub fn attach_initiator_role(&self, role: SessionPhaseRole) {
111	        if let Some(context) = &self.context {
112	            let _ = context.initiator_role.set(role);
113	        }
114	    }
115	
116	    /// Attach the derived, non-secret session correlation ID once the session
117	    /// token is known. The raw token is never retained or emitted.
118	    pub fn attach_session_token(&self, session_token: &[u8]) {
119	        if let Some(context) = &self.context {
120	            let _ = context.session_id.set(session_trace_id(session_token));
121	        }
122	    }
123	
124	    /// Record one low-frequency lifecycle boundary.
125	    pub fn record(&self, event: &'static str, outcome: Option<TransferLifecycleOutcome>) {
126	        let Some(context) = &self.context else {
127	            return;
128	        };
129	        let now = Instant::now();
130	        let record = TransferLifecycleEvent {
131	            schema: 1,
132	            run_id: context.run_id.to_string(),
133	            producer_seq: context.producer_seq.fetch_add(1, Ordering::Relaxed),
134	            unix_ns: SystemTime::now()
135	                .duration_since(UNIX_EPOCH)
136	                .unwrap_or_default()
137	                .as_nanos(),
138	            elapsed_ns: now.saturating_duration_since(context.origin).as_nanos(),
139	            event,
140	            initiator_role: context.initiator_role.get().copied(),
141	            session_id: context.session_id.get().map(ToString::to_string),
142	            outcome,
143	        };
144	        (context.emit)(record);
145	    }
146	
147	    /// Flush records already admitted to the asynchronous writer. Writer
148	    /// failure remains diagnostic-only and never changes a product result.
149	    pub fn flush(&self) {
150	        if let Some(context) = &self.context {
151	            (context.flush)();
152	        }
153	    }
154	
155	    fn from_env_with(
156	        read: impl FnMut(&str) -> Option<String>,
157	        writer: impl FnOnce(String, Instant) -> Self,
158	    ) -> Self {
159	        let origin = Instant::now();
160	        let Some(run_id) = trace_env_run_id(read) else {
161	            return Self::disabled();
162	        };
163	        writer(run_id, origin)
164	    }
165	
166	    fn stderr_writer(run_id: String, origin: Instant) -> Self {
167	        let stderr = std::io::stderr();
168	        Self::threaded_writer(run_id, origin, move |output| {
169	            let mut stderr = stderr.lock();
170	            match output {
171	                LifecycleWriterOutput::Line(line) => {
172	                    let _ = writeln!(stderr, "{line}");
173	                }
174	                LifecycleWriterOutput::Flush => {
175	                    let _ = stderr.flush();
176	                }
177	            }
178	        })
179	    }
180	
181	    fn threaded_writer(
182	        run_id: String,
183	        origin: Instant,
184	        mut output: impl FnMut(LifecycleWriterOutput) + Send + 'static,
185	    ) -> Self {
186	        enum WriterMessage {
187	            Event(Box<TransferLifecycleEvent>),
188	            Flush(std::sync::mpsc::SyncSender<()>),
189	        }
190	
191	        let (tx, rx) = std::sync::mpsc::channel::<WriterMessage>();
192	        let spawned = std::thread::Builder::new()
193	            .name("blit-transfer-lifecycle".into())
194	            .spawn(move || {
195	                while let Ok(message) = rx.recv() {
196	                    match message {
197	                        WriterMessage::Event(event) => {
198	                            output(LifecycleWriterOutput::Line(json_line(&event)));
199	                        }
200	                        WriterMessage::Flush(done) => {
201	                            output(LifecycleWriterOutput::Flush);
202	                            let _ = done.send(());
203	                        }
204	                    }
205	                }
206	            });
207	        if spawned.is_err() {
208	            return Self::disabled();
209	        }
210	
211	        let event_tx = tx.clone();
212	        let flush_tx = tx;
213	        Self::with_emitters(
214	            run_id,
215	            origin,
216	            Arc::new(move |event| {
217	                let _ = event_tx.send(WriterMessage::Event(Box::new(event)));
218	            }),
219	            Arc::new(move || {
220	                let (done_tx, done_rx) = std::sync::mpsc::sync_channel(0);
221	                if flush_tx.send(WriterMessage::Flush(done_tx)).is_ok() {
222	                    let _ = done_rx.recv();
223	                }
224	            }),
225	        )
226	    }
227	
228	    fn with_emitters(
229	        run_id: String,
230	        origin: Instant,
231	        emit: Arc<EventEmitter>,
232	        flush: Arc<FlushEmitter>,
233	    ) -> Self {
234	        Self {
235	            context: Some(Arc::new(LifecycleContext {
236	                run_id: Arc::from(run_id),
237	                origin,
238	                producer_seq: AtomicU64::new(0),
239	                initiator_role: OnceLock::new(),
240	                session_id: OnceLock::new(),
241	                emit,
242	                flush,
243	            })),
244	        }
245	    }
246	}
247	
248	fn json_line(event: &TransferLifecycleEvent) -> String {
249	    match serde_json::to_string(event) {
250	        Ok(line) => format!("[transfer-lifecycle] {line}"),
251	        Err(err) => format!("[transfer-lifecycle] serialization_error={err}"),
252	    }
253	}
